#include <stdio.h>
#include <stdlib.h>

#define NUM_NUMBERS 5

int main(void) {
    int numbers[NUM_NUMBERS];
    int guessed_positions[NUM_NUMBERS] = {0};
    int score = 0;
    char guess;

    // Generate 5 unique random numbers (1-10)
    for (int i = 0; i < NUM_NUMBERS; ++i) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (numbers[i] == 0);
    }

    // Hide numbers initially
    printf("Numbers: ");
    for (int i = 0; i < NUM_NUMBERS; ++i) {
        printf("*");
    }
    printf("\n");

    // Game loop
    for (int i = 0; i < NUM_NUMBERS; ++i) {
        printf("Pick position %d (1-%d): ", i + 1, NUM_NUMBERS);
        scanf("%d", &guessed_positions[i]);

        printf("Guess even or odd (E/O): ");
        scanf(" %c", &guess);

        if ((numbers[guessed_positions[i] - 1] % 2 == 0 && guess == 'E') ||
            (numbers[guessed_positions[i] - 1] % 2 != 0 && guess == 'O')) {
            printf("Correct!\n");
            score += 5;
        } else {
            printf("Wrong\n");
        }

        // Reveal the number
        printf("Number at position %d: %d\n", guessed_positions[i], numbers[guessed_positions[i] - 1]);
    }

    // Display final score
    printf("Final Score: %d\n", score);

    return 0;
}
